def solve(frames: list[str]) -> dict[str, float]:
    """
    Compute channel averages of normalized token sums from valid frames.

    Args:
        frames: A list of Fluxon frame strings.

    Returns:
        A dictionary mapping channel names to the average normalized token sum
        for that channel (only valid frames are considered).
    """
    totals: dict[str, float] = {}
    counts: dict[str, int] = {}

    for frame in frames:
        try:
            packet = decode_fluxon_frame(frame)
        except ValueError:
            continue

        # Parse "FXN::<version>::<channel>::<token1>::<token2>::..."
        if not packet.startswith("FXN::"):
