        token_sum = sum(token_value(t) for t in tokens)
        normalized_sum = normalize_channel_value(token_sum, channel)

        totals[channel] = totals.get(channel, 0.0) + normalized_sum
        counts[channel] = counts.get(channel, 0) + 1

    return {
        channel: totals[channel] / counts[channel]
        for channel in totals
    }
